// Other Internal Functions
//
private var _firrtlPorts: Option[Seq[Port]] = None

private[chisel3] def checkPorts(): Unit = {
  for ((port, source, _) <- getModulePortsAndLocators) {
    if (port._computeName(None).isEmpty) {
      Builder.error(
        s"Unable to name port $port in $this, " +
          s"try making it a public field of the Module ${source.makeMessage()}"
      )(UnlocatableSourceInfo)
    }
  }
}

/** Private variable that tracks if a module is public. */
private[chisel3] def _isPublic: Boolean = false

/** Finalize name for an id created during this RawModule's constructor.
  *
  * @param id The id to finalize.
  */
private def nameId(id: HasId) = id match {
  case id: ModuleClone[_]   => id.setRefAndPortsRef(_namespace) // special handling
  case id: InstanceClone[_] => id.setAsInstanceRef()
  case id: BaseModule       => id._forceName(default = id.desiredName, _namespace)
  case id: MemBase[_]       => id._forceName(default = "MEM", _namespace)
  case id: stop.Stop        => id._forceName(default = "stop", _namespace)
  case id: assert.Assert    => id._forceName(default = "assert", _namespace)
  case id: assume.Assume    => id._forceName(default = "assume", _namespace)
  case id: cover.Cover      => id._forceName(default = "cover", _namespace)
  case id: printf.Printf    => id._forceName(default = "printf", _namespace)
  case id: DynamicObject => {
    // Force name of the DynamicObject, and set its Property[ClassType] type's ref to the DynamicObject.
    // The type's ref can't be set upon instantiation, because the DynamicObject hasn't been named yet.
    // This also updates the source Class ref to the DynamicObject ref now that it's named.
    id._forceName(default = "_object", _namespace)
    id.getReference.setRef(id.getRef)
    id.setSourceClassRef()
  }
  case id: StaticObject => {
    // Set the StaticObject's ref and Property[ClassType] type's ref to the BaseModule for the Class.
    // These refs can't be set upon instantiation, because the ModuleClone hasn't been named yet.
    id.setRef(id.getInstanceModule.getRef)
    id.getReference.setRef(id.getInstanceModule.getRef)
  }
  case id: Data =>
    if (id.isSynthesizable) {
      id.topBinding match {
        case OpBinding(_, _) =>
          id._forceName(default = "_T", _namespace)
        case MemoryPortBinding(_, _) =>
          id._forceName(default = "MPORT", _namespace)
        case PortBinding(_) =>
          id._forceName(default = "PORT", _namespace, true, x => ModuleIO(this, x))
        case RegBinding(_, _) =>
          id._forceName(default = "REG", _namespace)
        case WireBinding(_, _) =>
          id._forceName(default = "_WIRE", _namespace)
        case InstanceChoiceBinding(_, _) =>
          id._forceName(default = "_INST", _namespace)

}

// This function (finally) issues the connection operation
private def issueConnect(sink: Element, source: Element)(implicit sourceInfo: SourceInfo): Unit = {
  // If the source is a DontCare, generate a DefInvalid for the sink,
  //  otherwise, issue a Connect.
  source.topBinding match {
    case b: DontCareBinding => pushCommand(DefInvalid(sourceInfo, sink.lref))
    case _ => pushCommand(Connect(sourceInfo, sink.lref, source.ref))
  }
}

// This function checks if element-level connection operation allowed.
// Then it either issues it or throws the appropriate exception.
def elemConnect(
  implicit sourceInfo: SourceInfo,
  _sink:               Element,
  _source:             Element,
  context_mod:         BaseModule
): Unit = {
  // Reify sink and source if they're views.
  val (sink, writable) = reify(_sink)
  val (source, _) = reify(_source)

  checkConnect(sourceInfo, sink, source, context_mod)
  writable.reportIfReadOnlyUnit(issueConnect(sink, source))
}

def propConnect(
  sourceInfo: SourceInfo,
  sinkProp:   Property[_],
