): Unit = {
  implicit val info: SourceInfo = sourceInfo
  // Reify sink and source if they're views.
  val (sink, writable) = reify(sinkProp)
  val (source, _) = reify(sourceProp)

  checkConnect(sourceInfo, sink, source, context)
